#include <iostream>
using namespace std;

int main() {
    // 1. Стандартний цикл FOR
    cout << "Рахуємо до 5: ";
    for (int i = 1; i <= 5; i++) {
        cout << i << " ";
    }
    cout << "

";

    // 2. Цикл WHILE для обробки меню користувача
    int password;
    cout << "Введіть пін-код: ";
    cin >> password;

    int attempts = 1;
    while (password != 1234) {
        if (attempts >= 3) {
            cout << "Карту заблоковано! Вичерпано 3 спроби." << endl;
            break; // ДОСТРОКОВИЙ ВИХІД
        }
        cout << "Невірно. Спробуйте ще: ";
        cin >> password;
        attempts++;
    }

    if (password == 1234) {
        cout << "Доступ дозволено! Пінкапітал на рахунку." << endl;
    }

    // 3. З використанням continue
    cout << "
Непарні числа від 1 до 6: ";
    for (int j = 1; j <= 6; j++) {
        if (j % 2 == 0) {
            continue; // Якщо число парне, пропускаємо його вивід
        }
        cout << j << " ";
    }
    cout << endl;

    return 0;
}
